261	    fn movie(self) -> Arc<SwfMovie> {
262	        self.0.movie()
263	    }
264	
265	    fn post_instantiation(
266	        self,
267	        context: &mut UpdateContext<'gc>,
268	        _init_object: Option<Object<'gc>>,
269	        _instantiated_by: Instantiator,
270	        _run_frame: bool,
271	    ) {
272	        self.set_default_instance_name(context);
273	
274	        if self.0.object.get().is_none() {
275	            let object = Object::new_with_native(
276	                &context.strings,
277	                Some(context.avm1.prototypes(self.swf_version()).button),
278	                NativeObject::Button(self),
279	            );
280	            let obj = unlock!(Gc::write(context.gc(), self.0), Avm1ButtonData, object);
281	            obj.set(Some(object));
282	        }
283	
284	        if !self.0.initialized.get() {
285	            let mut new_children = Vec::new();
286	
287	            self.set_state(context, ButtonState::Up);
288	            self.0.initialized.set(true);
289	
290	            for record in &self.0.shared.cell.borrow().records {
291	                if record.states.contains(swf::ButtonState::HIT_TEST) {
292	                    match context
293	                        .library
294	                        .library_for_movie_mut(self.0.movie())
295	                        .instantiate_by_id(record.id, context.gc_context)
296	                    {
297	                        Some(child) => {
298	                            child.set_matrix(record.matrix.into());
299	                            child.set_parent(context, Some(self.into()));
300	                            child.set_depth(record.depth.into());
301	                            new_children.push((child, record.depth.into()));
302	                        }
303	                        None => {
304	                            tracing::error!(
305	                                "Button ID {}: could not instantiate child ID {}",
306	                                self.0.shared.id,
307	                                record.id,
308	                            );
309	                        }
310	                    }
311	                }
312	            }
313	
314	            let write = unlock!(Gc::write(context.gc(), self.0), Avm1ButtonData, cell);
315	            let mut hit_bounds = Rectangle::INVALID;
316	            for (child, depth) in new_children {
317	                child.post_instantiation(context, None, Instantiator::Movie, false);
318	                write.borrow_mut().hit_area.insert(depth, child);
319	                hit_bounds = hit_bounds.union(&child.local_bounds(BoundsMode::Engine));
320	            }
321	            write.borrow_mut().hit_bounds = hit_bounds;
322	        }
323	    }
