413	impl<'gc> TDisplayObject<'gc> for Avm2Button<'gc> {
414	    fn base(self) -> Gc<'gc, DisplayObjectBase<'gc>> {
415	        HasPrefixField::as_prefix_gc(self.raw_interactive())
416	    }
417	
418	    fn instantiate(self, mc: &Mutation<'gc>) -> DisplayObject<'gc> {
419	        Self(Gc::new(mc, (*self.0).clone())).into()
420	    }
421	
