use swf::*;

fn color(r: u8, g: u8, b: u8) -> Color {
    Color { r, g, b, a: 255 }
}

fn rect_shape(id: CharacterId, x: f64, y: f64, w: f64, h: f64, fill: Color) -> Tag<'static> {
    Tag::DefineShape(Box::new(Shape {
        version: 3,
        id,
        shape_bounds: Rectangle {
            x_min: Twips::from_pixels(x),
            x_max: Twips::from_pixels(x + w),
            y_min: Twips::from_pixels(y),
            y_max: Twips::from_pixels(y + h),
        },
        edge_bounds: Rectangle {
            x_min: Twips::from_pixels(x),
            x_max: Twips::from_pixels(x + w),
            y_min: Twips::from_pixels(y),
            y_max: Twips::from_pixels(y + h),
        },
        flags: ShapeFlag::empty(),
        styles: ShapeStyles {
            fill_styles: vec![FillStyle::Color(fill)],
            line_styles: vec![],
        },
        shape: vec![
            ShapeRecord::StyleChange(Box::new(StyleChangeData {
                move_to: Some(Point::from_pixels(x, y)),
                fill_style_0: None,
                fill_style_1: Some(1),
                line_style: None,
                new_styles: None,
            })),
            ShapeRecord::StraightEdge { delta: PointDelta::from_pixels(w, 0.0) },
            ShapeRecord::StraightEdge { delta: PointDelta::from_pixels(0.0, h) },
            ShapeRecord::StraightEdge { delta: PointDelta::from_pixels(-w, 0.0) },
            ShapeRecord::StraightEdge { delta: PointDelta::from_pixels(0.0, -h) },
        ],
    }))
}

fn place(id: CharacterId, depth: Depth, x: f64, y: f64) -> Tag<'static> {
    Tag::PlaceObject(Box::new(PlaceObject {
        version: 2,
        action: PlaceObjectAction::Place(id),
        depth,
        matrix: Some(Matrix::translate(Twips::from_pixels(x), Twips::from_pixels(y))),
        color_transform: None,
        ratio: None,
        name: None,
        clip_depth: None,
        class_name: None,
        filters: None,
        background_color: None,
        blend_mode: None,
        clip_actions: None,
        has_image: false,
        is_bitmap_cached: None,
        is_visible: None,
        amf_data: None,
    }))
}

fn modify(depth: Depth, x: f64, y: f64) -> Tag<'static> {
    Tag::PlaceObject(Box::new(PlaceObject {
        version: 2,
        action: PlaceObjectAction::Modify,
        depth,
        matrix: Some(Matrix::translate(Twips::from_pixels(x), Twips::from_pixels(y))),
        color_transform: None,
        ratio: None,
        name: None,
        clip_depth: None,
        class_name: None,
        filters: None,
        background_color: None,
        blend_mode: None,
        clip_actions: None,
        has_image: false,
        is_bitmap_cached: None,
        is_visible: None,
        amf_data: None,
    }))
}

fn main() {
    let header = Header {
        compression: Compression::Zlib,
        version: 10,
        stage_size: Rectangle {
            x_min: Twips::ZERO,
            x_max: Twips::from_pixels(100.0),
            y_min: Twips::ZERO,
            y_max: Twips::from_pixels(100.0),
        },
        frame_rate: Fixed8::from_f32(1.0),
        num_frames: 3,
    };

    let movie = Sprite {
        id: 10,
        num_frames: 3,
        tags: vec![
            place(1, 1, 0.0, 0.0),
            Tag::ShowFrame,
            modify(1, 25.0, 0.0),
            Tag::ShowFrame,
            modify(1, 50.0, 0.0),
            Tag::ShowFrame,
        ],
    };

    let button = Button {
        id: 20,
        is_track_as_menu: false,
        records: vec![ButtonRecord {
            states: ButtonState::UP | ButtonState::OVER | ButtonState::DOWN | ButtonState::HIT_TEST,
            id: 10,
            depth: 1,
            matrix: Matrix::IDENTITY,
            color_transform: ColorTransform::IDENTITY,
            filters: vec![],
            blend_mode: BlendMode::Normal,
        }],
        actions: vec![],
    };

    let tags = vec![
        Tag::FileAttributes(FileAttributes::IS_ACTION_SCRIPT_3),
        Tag::SetBackgroundColor(color(255, 255, 255)),
        rect_shape(1, 0.0, 0.0, 10.0, 10.0, color(255, 0, 0)),
        Tag::DefineSprite(movie),
        Tag::DefineButton2(Box::new(button)),
        Tag::PlaceObject(Box::new(PlaceObject {
            version: 3,
            action: PlaceObjectAction::Place(20),
            depth: 1,
            matrix: Some(Matrix::translate(Twips::from_pixels(20.0), Twips::from_pixels(20.0))),
            color_transform: None,
            ratio: None,
            name: None,
            clip_depth: None,
            class_name: None,
            filters: None,
            background_color: None,
            blend_mode: None,
            clip_actions: None,
            has_image: false,
            is_bitmap_cached: Some(true),
            is_visible: None,
            amf_data: None,
        })),
        Tag::ShowFrame,
        Tag::ShowFrame,
        Tag::ShowFrame,
    ];

    let path = "/testbed/tests/tests/swfs/visual/cache_as_bitmap/avm2_button/test.swf";
    let file = std::fs::File::create(path).unwrap();
    let writer = std::io::BufWriter::new(file);
    swf::write_swf(&header, &tags, writer).unwrap();
}

